import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "11:30。灣岸署。問話室。不是正式逮捕。但比昨晚在站務室裡的臨時聽取嚴肅得多。桌子。錄音筆。表格。兩名警員坐在對面。一名負責問。一名負責寫。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "牆上的時鐘。11:31。她看了一眼。和手機對了一下。差兩秒。手機11:30:58。時鐘11:31:00。她不知道哪個比較準。她把手機放在桌上。螢幕朝上。保持開機。通知裡寫的。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "朝倉澪小姐。關於昨夜灣岸新交通限制區傷害事件及搬送後死亡一案，請配合補充說明。身分證件確認過了。我們開始錄音。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "好。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音比她預期的平。一夜沒睡。但聲音沒有抖。身體在抖。手放在膝蓋上。膝蓋在抖。但聲音是平的。像把所有東西都壓進了一條很窄的縫裡。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "請說明你昨夜為什麼出現在灣岸新交通站。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯能說的真話。收到匿名訊息。訊息提到悠真。訊息指定第七車。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不能說的真相。我經歷過第一輪。我知道千田會死在那裡。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我收到匿名訊息，內容提到我弟弟朝倉悠真，指定了第七車。我弟弟目前失蹤中，我認為這和他有關，所以去了。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "匿名訊息的來源？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "不明。手機簡訊。沒有寄件號碼。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "訊息內容是否保留？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "有。我可以提供截圖。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "負責記錄的警員寫了幾行字。筆在紙上沙沙地響。她看著他寫。字很整齊。欄位很清楚。每一句話都被放進一個格子裡。她的話進了格子之後就變得很小。很規矩。像被修剪過的樹。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "你為什麼提早抵達？訊息指定的時間是什麼？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "訊息沒有指定明確時間。只指定了第七車。我查了灣岸新交通的班次。第七車在夜間限制區運行。我提前到場是為了確認車次。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "你如何知道第七車的運行資訊？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "灣岸新交通的公開時刻表。網路上查得到。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "到場後你做了什麼？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我在月台等候。21:04 左右，第七車進站。我聽見站務人員和維修人員在溝通。他們提到第七車。也提到中央流。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "中央流？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "是的。我不確定具體意思。但他們用了這個詞。我覺得對方的行為不尋常。維修人員穿著制服、戴口罩和帽子。他們引導一名男性進入施工通道。我跟上去。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "為什麼跟進限制區？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯因為我知道那個人會死。但我不能這樣說。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "因為訊息提到第七車。維修人員的行為不像是正常維修。我懷疑和我弟弟的失蹤有關。我跟上去想確認。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "跟進施工通道後看到了什麼？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "側門。有綠光。然後我看見那名男性倒下。他受傷了。肋下。有血。我呼救。站務人員和救護人員抵達。他被搬送到灣岸中央急救醫療中心。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "你認識那名男性嗎？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯千田浩介。我認識。第一輪他死在第七車。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他把外殼塞給我。他說不要救東京。但我不能說這些。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "不認識。我昨晚在站務室做初步筆錄時才知道他叫千田浩介。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "問話的警員看了她一眼。不是懷疑。是在確認她的表情和陳述是否一致。她不知道自己的表情是什麼樣。一夜沒睡的臉。應該像一張被揉皺的紙。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "你剛才提到你弟弟朝倉悠真失蹤中。請說明你弟弟的失蹤與千田浩介先生的死亡之間的關聯。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯關聯。關聯是什麼。是同一片黑色海。是同一組夢。是同一個研究中心。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯是同一個把簡訊代發的機制。是千田兩次都說簡訊不是悠真。是——", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "匿名訊息同時提到我弟弟和第七車。千田先生在第七車相關區域受傷。我認為訊息發送者知道兩件事的關聯。但我沒有直接證據。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "你有沒有想過，訊息可能是刻意引導你到現場？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯⋯⋯", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他說對了。訊息確實是引導。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯但引導我去的目的是什麼。是讓我看見千田死。是讓我變成目擊者。是讓我變成——", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "有可能。但我不知道對方的目的。我只知道訊息提到我弟弟。我不能忽略任何和我弟弟有關的線索。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "警員點了一下頭。不是同意。是在記錄。他翻了一頁表格。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "關於你弟弟的失蹤案件。你之前已經報案。目前由少年課另案處理。今天我們補充說明的範圍是千田浩介先生死亡前後的事。你弟弟的失蹤，我們會另案確認。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯⋯⋯另案。另案確認。分開。他們要把千田和悠真拆開。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯千田死亡歸千田死亡。悠真失蹤歸悠真失蹤。兩個編號。兩個承辦。兩個欄位。我說它們有關聯。他們說：請分開陳述。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不是因為他們蠢。是因為他們的表格沒有「同一件事」這個欄位。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他們有欄位。欄位是設計好的。千田死亡是交通限制區傷害及搬送後死亡。悠真失蹤是失蹤少年案件。兩個欄位之間沒有連接線。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我畫的線放不進去。他們不是不看。是放不進去。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我明白。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她說「我明白」的時候。聲音沒有升高。也沒有降低。很平。像在讀一個已經寫好的答案。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "你提到維修人員。能否描述更多細節？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "制服。灣岸新交通的維修制服。深色。戴口罩。帽子壓得很低。我看不到臉。他們的動作很熟練。不像臨時出現。像事先知道路線。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "維修人員有沒有對你說話？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "沒有直接對我說話。但我聽見他們之間的對話。提到第七車。中央流。還有——", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她停了一下。嘴唇動了動。像在確認要不要說下一個詞。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "搬送。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "搬送？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "是的。他們提到搬送。在千田先生倒下之前。他們已經在討論搬送。這不正常。一般人不會在事故發生之前就討論搬送。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "警員寫了幾行。沒有評論。他只是在記錄。把她的話放進欄位。搬送。事先討論。可疑。這些字進了表格之後就變成了「待查證」。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "匿名訊息裡有沒有提到「悠真留下的那件東西」？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯⋯⋯來了。那件東西。他們問了。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不能迴避。迴避會讓他們覺得我在藏東西。我在藏東西。但不能讓他們覺得我在藏證據。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯小鏡子不是千田案的證據。它是悠真留給我的。我可以承認它存在。可以承認它是什麼。只是今天沒帶。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "有。訊息裡提到「悠真留下的那件東西」。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "具體是什麼？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "一面小鏡子。悠真失蹤前留給我的。今天沒有帶來。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "問話的警員抬了一下眼。記錄的警員停筆。然後繼續寫。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "為什麼沒帶？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我不知道它會被問到。它一直放在家裡。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這是真話。她不知道警方會追問到這裡。她也不知道匿名訊息裡的「那件東西」會被警方當成一個需要確認的項目。她只是不想讓小鏡子進入流程。但這句話本身是真的。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "小鏡子上有什麼特徵？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯刮痕。背面。像數字。像7。但不能說7。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯說了會被追問。7是什麼。為什麼是7。和第七車有什麼關係。和東京方案有什麼關係。這些我答不了。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "背面有一些刮痕。不確定是什麼。可能是數字。可能是磨損。我沒有仔細辨識過。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "下次請帶來確認。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我明白。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她說「我明白」的時候。手指在膝蓋上攥了一下。指甲掐進掌心。很輕。但夠痛。夠讓她清醒。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯下次。下次要帶來。他們記錄了。小鏡子已經進入官方視野了。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不是扣押。不是搜索。只是一句「下次請帶來確認」。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯但這句話的意思是：他們知道它存在了。知道它是什麼了。知道它在哪裡了。它不再完全隱形了。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯暫時安全。只是暫時。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "你認為你弟弟的簡訊不是本人發送的。這個判斷的依據是什麼？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "語氣。用詞。悠真平時不會那樣說話。他失蹤當天傳來的簡訊語氣正常。太正常了。悠真傳訊息的時候通常會有錯字。會用遊戲用語。那條簡訊沒有。太完整了。不像他。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "這是你的主觀判斷？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "是。但我是他姐姐。和他一起生活。我了解他的通訊習慣。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "警員寫了幾行。家屬主觀判斷。這幾個字會進入記錄。家屬主觀判斷。五個字。把她的觀察裝進了一個很小的盒子裡。蓋上蓋子。貼上標籤。存檔。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "除了匿名訊息和簡訊，你還有沒有其他認為與千田浩介先生死亡案件相關的資訊？", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯有。黑色海。no_moon。bluefish_7。睡眠研究。夢話錄音。座標。筑波。小鏡子背面的7。這些全都有關。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯但我不能說。說了就會被分類。被翻譯。被換名字。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯黑色海變成夢境內容。no_moon 變成不明網路帳號。bluefish_7 變成遊戲帳號活動紀錄。每一樣東西進了表格就不再是原來的樣子。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "沒有。目前能說的都在這裡了。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "12:20。問話持續了將近一個小時。她的背很僵。椅子是硬的。腰部沒有支撐。她一直坐得很直。不是因為放鬆。是因為不敢鬆。鬆了就會垮。垮了就會漏。漏了就會被記錄。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "今天的補充說明到此。後續如有需要會再聯絡。請保持手機開機。近期請不要離開東京都內太遠。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "好。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "另外，關於小鏡子。下次請務必帶來。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我明白。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "12:35。她站起來。椅子往後刮了一聲。腿還是軟的。她扶了一下桌沿。站穩。拿起手機。拿起背包。藍色筆記在裡面。黑色筆記在家裡的抽屜裡。小鏡子也在。舊掌機在車站旁的置物櫃裡。14號。鑰匙在錢包夾層。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走出問話室。走廊。白色的燈。很亮。很平。地上是灰色的塑膠地板。她的鞋踩在上面。每一步都很輕。但每一步都有回音。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他們不是壞人。他們在做他們的工作。他們有表格。有欄位。有流程。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他們把我的話放進去。一句一句。很仔細。很整齊。但千田和悠真之間那條線放不進去。不是他們不願意。是表格沒有那個欄位。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我說了能說的真話。我沒有說不能說的真相。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我承認了小鏡子。他們記錄了。下次要帶來。小鏡子暫時安全。但只是暫時。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯出來了。現在。置物櫃。舊掌機。bluefish_7。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她推開灣岸署的自動門。外面的光比裡面暗。灰的。有風。她站在門口。深吸一口氣。空氣有柏油和消毒水混在一起的味道。她把手機拿出來。看了一眼時間。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "12:36。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她往車站走。置物櫃。14號。鑰匙在錢包裡。舊掌機在裡面。bluefish_7 在裡面。另一個沒有回來的孩子在裡面。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯先去拿掌機。然後查 bluefish_7。官方版本要她分開回答。但她的手知道。千田和悠真是同一件事。同一片海。", background: Background.Chapter_10_Ch10_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走。腿還是軟的。但比進去之前穩了一點。因為她知道接下來要做什麼。", background: Background.Chapter_10_Ch10_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是回答警察的問題。是去找一個叫 bluefish_7 的帳號。去找一條官方表格放不進去的線。", background: Background.Chapter_10_Ch10_Act3_S0 },
];
